from jinja2.ext import i18n

env = Environment(extensions=[i18n])

def gettext(s):
    return s.upper()

def ngettext(s, p, n):
    return (s if n == 1 else p).upper()

def dgettext(d, s):
    return f'[{d}]{s}'

def dngettext(d, s, p, n):
    return f'[{d}]' + (s if n == 1 else p)

env.install_gettext_callables(gettext, ngettext, newstyle=False)
env.globals['dgettext'] = dgettext
env.globals['dngettext'] = dngettext

